import LoadingEllipsis from '#components/LoadingEllipsis';

import {
  BestFor,
  Body,
  BuyButton,
  Footer,
  Header,
  Image,
  Price,
  ReviewButton,
  Rating,
  Title,
  TitleOverlapFacilitator,
  Wrapper,
} from './ProductCarouselCard.styles';
import propTypes from './ProductCarouselCard.types';

const ProductCarouselCard = ({
  anchorHref,
  bestForPrefixed,
  checkbox,
  image,
  intro,
  prettyPrice,
  rating,
  title,
  vendorLink,
  isLoading = false,
  isAvailable = true,
}) => {
  const price = prettyPrice.split('.')[0];

  return (
    <Wrapper>
      <Image>{image}</Image>
      <Header>
        <Title>
          <TitleOverlapFacilitator>{title}</TitleOverlapFacilitator>
        </Title>
        <BestFor href={anchorHref}>
          <div>{bestForPrefixed}</div>
        </BestFor>
        <Rating value={rating} />
      </Header>
      <Body
        dangerouslySetInnerHTML={{
          __html: intro,
        }}
      />
      <Footer>
        <ReviewButton href={anchorHref}>Read review</ReviewButton>
        <Price>
          {isLoading ? <LoadingEllipsis /> : <strong>{price}</strong>}
        </Price>
        <BuyButton
          href={vendorLink}
          target="_blank"
          rel="noreferrer"
          disabled={!isAvailable}
          isExternal={true}
        >
          {isAvailable ? 'Buy now' : 'Unavailable'}
        </BuyButton>
        {checkbox}
      </Footer>
    </Wrapper>
  );
};

ProductCarouselCard.propTypes = propTypes;

export default ProductCarouselCard;
