import { styled } from 'styled-components';

import Button from '#components/Button';
import {
  BUTTON_VARIANT_TERTIARY,
  BUTTON_VARIANT_SECONDARY,
} from '#components/Button/Button.constants';
import StarRating from '#components/StarRating';

import * as device from '#theme/devices';

import clampLines from '#utils/clampLines';

import {
  TILE_WIDTH_MOBILE,
  TILE_WIDTH_TABLET,
  TILE_WIDTH_LAPTOP,
  FOOTER_SPACING,
} from './ProductCarouselCard.constants';

export const Wrapper = styled.article`
  --padding-x: ${(props) => props.theme.spacing.x1}px;
  --padding-bottom: ${({ theme }) => theme.spacing.x1_5}px;
  --tile-width: ${TILE_WIDTH_MOBILE}px;
  --spacing: ${(props) => props.theme.spacing.x1}px;
  --border: 1px solid ${(props) => props.theme.color.grey50};
  --border-radius: ${(props) => props.theme.dimension.outerArea.borderRadius};
  display: flex;
  width: var(--tile-width);
  height: 100%;
  box-sizing: border-box;
  flex-direction: column;
  padding: 0 var(--padding-x) var(--padding-bottom);
  border-radius: var(--border-radius);
  background-color: ${({ theme }) => theme.color.canvas.base};
  text-align: center;

  @media ${device.tablet} {
    --padding-x: ${({ theme }) => theme.spacing.x2}px;
    --padding-bottom: ${({ theme }) => theme.spacing.x2}px;
    --tile-width: ${TILE_WIDTH_TABLET}px;
  }

  @media ${device.laptop} {
    --padding-x: ${({ theme }) => theme.spacing.x1_5}px;
    --spacing: ${({ theme }) => theme.spacing.x1_5}px;
    --tile-width: ${TILE_WIDTH_LAPTOP}px;
  }
`;

export const Image = styled.div`
  overflow: hidden;
  margin: 0 calc(var(--padding-x) * -1) 12px;
  border-radius: var(--border-radius) var(--border-radius) 0 0;
  aspect-ratio: 4 / 3;

  img {
    display: block;
  }
`;

export const Rating = styled(StarRating)`
  justify-content: center;
  margin: 0 auto;
`;

export const Title = styled.strong`
  --font-size: 17px;
  --line-height: 21px;
  --lines: 3;
  display: block;
  border-top: var(--border);
  font: bold var(--font-size) / var(--line-height)
    ${({ theme }) => theme.fontFamily.primaryFont};

  @media ${device.tablet} {
    --font-size: 19px;
    --line-height: 23px;
  }

  @media ${device.laptop} {
    --font-size: 24px;
    --line-height: 28px;
  }
`;

export const TitleOverlapFacilitator = styled.span`
  /*
    We need to allow for the text to overspill the boundary of the title
    otherwise the truncation ellipsis is clipped as it is not considered when
    calculating the width of the wrapper. If padding is used then overflowing
    text is visible.
  */
  display: block;
  padding: var(--spacing) var(--padding-x) 0 0;
  margin: 0 calc(var(--padding-x) * -1) var(--spacing) 0;
  ${clampLines('--lines', '--line-height', true)}
`;

export const BestFor = styled.a`
  --lines: 3;
  --font-size: 14px;
  --line-height: 18px;
  color: ${({ theme }) => theme.color.ink.base};
  font: bold var(--font-size) / var(--line-height)
    ${({ theme }) => theme.fontFamily.secondaryFont};
  transition: ${({ theme }) => theme.transition.link};

  /* @todo: replace with correct semantic name for the link and hover */

  &:hover,
  &:focus,
  &:active {
    color: ${({ theme }) => theme.color.actionBrand.base};
  }

  div {
    padding-right: var(--padding-x);
    margin-right: calc(var(--padding-x) * -1);
    ${clampLines('--lines', '--line-height', true)}
  }

  @media ${device.tablet} {
    --font-size: 16px;
    --line-height: 20px;
  }

  @media ${device.laptop} {
    --font-size: 18px;
    --line-height: 22px;
  }
`;

export const Header = styled.header`
  display: flex;
  flex-direction: column;
  row-gap: var(--spacing);

  ${BestFor} {
    order: 1;
  }

  ${Rating} {
    order: 2;
  }

  ${Title} {
    order: 3;
  }
`;

export const Body = styled.div`
  --lines: 5;
  --line-height: 17px;
  --font-size: 13px;
  padding: var(--spacing) 0 0;
  border-top: var(--border);
  font: normal var(--font-size) / var(--line-height)
    ${({ theme }) => theme.fontFamily.secondaryFont};

  @media ${device.laptop} {
    --font-size: 16px;
    --line-height: 20px;
  }

  p {
    padding-right: var(--padding-x);
    margin: 0 calc(var(--padding-x) * -1) 0 0;
    font: inherit;
    ${clampLines('--lines', '--line-height', true)}
  }
`;

export const Footer = styled.footer`
  margin-top: auto;
`;

export const ReviewButton = styled(Button).attrs({
  forwardedAs: 'a',
  size: 'large',
  variant: BUTTON_VARIANT_TERTIARY,
})`
  margin-bottom: ${(props) => props.theme.spacing.x0_5}px;

  @media ${device.laptop} {
    margin-bottom: ${(props) => props.theme.spacing.x1_5}px;
  }
`;

export const Price = styled.div`
  --font-size: 17px;
  --line-height: 21px;
  display: flex;
  min-height: var(--line-height);
  flex-flow: row nowrap;
  justify-content: center;
  padding: var(--spacing) 0;
  border-top: var(--border);
  border-bottom: var(--border);
  font: bold var(--font-size) / var(--line-height)
    ${({ theme }) => theme.fontFamily.secondaryFont};

  @media ${device.tablet} {
    --font-size: 19px;
    --line-height: 23px;
  }

  @media ${device.laptop} {
    --font-size: 24px;
    --line-height: 28px;
  }
`;

export const BuyButton = styled(Button).attrs({
  forwardedAs: 'a',
  variant: BUTTON_VARIANT_SECONDARY,
})`
  margin: ${FOOTER_SPACING}px 0;

  &:last-child {
    margin-bottom: 0;
  }
`;
