import PropTypes from 'prop-types';

export default {
  /** Product ID */
  id: PropTypes.string.isRequired,
  /** Preformed href string to link to a product DOM element */
  anchorHref: PropTypes.string.isRequired,
  /** Preformed id string to add to a product DOM element */
  anchorId: PropTypes.string.isRequired,
  /** 'bestFor' property prefixed with the words "Best for"  */
  bestForPrefixed: PropTypes.string.isRequired,
  /** Product image */
  image: PropTypes.element.isRequired,
  /** Introduction paragraph, usually the first line of the description */
  intro: PropTypes.string.isRequired,
  /** Price with currency symbol */
  prettyPrice: PropTypes.string,
  /** Product rating  */
  rating: PropTypes.number.isRequired,
  /** Product name */
  title: PropTypes.string.isRequired,
  /** Link to recommended retailer */
  vendorLink: PropTypes.string.isRequired,
  /** Whether or not the 'vendorLink' is and external or internal URL */
  isExternal: PropTypes.bool,
};
